from dataclasses import dataclass, field
from typing import Optional

@dataclass
class GoalPriority:
    goal_id: str
    objective: str
    impact: float        # 0.0 – 1.0: how much the goal advances the overall mission
    urgency: float       # 0.0 – 1.0: time pressure (deadline proximity, blocking others)
    dependency_count: int = 0   # goals blocked until this one is done
    cost_estimate: float = 1.0  # estimated steps / tokens relative to budget

    @property
    def score(self) -> float:
        # WSJF-style: value / cost, boosted by urgency
        value = (self.impact + self.urgency) / 2
        dependency_boost = 1 + 0.2 * self.dependency_count
        return (value * dependency_boost) / max(self.cost_estimate, 0.1)

    def __lt__(self, other: "GoalPriority") -> bool:
        return self.score > other.score   # higher score = higher priority


def sort_goals(goals: list[GoalPriority]) -> list[GoalPriority]:
    return sorted(goals)   # uses __lt__ above

from collections import defaultdict, deque

@dataclass
class ScheduledGoal:
    priority: GoalPriority
    depends_on: list[str] = field(default_factory=list)  # goal_ids


def dependency_ordered_queue(
    scheduled: list[ScheduledGoal],
) -> list[GoalPriority]:
    """Topological sort with priority tie-breaking inside each wave."""
    id_to_sg = {sg.priority.goal_id: sg for sg in scheduled}
    in_degree = {sg.priority.goal_id: len(sg.depends_on) for sg in scheduled}
    dependents = defaultdict(list)
    for sg in scheduled:
        for dep in sg.depends_on:
            dependents[dep].append(sg.priority.goal_id)

    ready = sorted(
        [sg.priority for sg in scheduled if in_degree[sg.priority.goal_id] == 0]
    )
    result = []
    while ready:
        current = ready.pop(0)   # highest-score first
        result.append(current)
        for dep_id in dependents[current.goal_id]:
            in_degree[dep_id] -= 1
            if in_degree[dep_id] == 0:
                ready.append(id_to_sg[dep_id].priority)
                ready.sort()   # re-sort after insertion
    return result

REPRIORITIZE_PROMPT = """Re-score the following remaining goals given new information.

Mission: {mission}

New information:
{update}

Remaining goals (current scores shown):
{goals_text}

Return updated JSON array with revised impact, urgency, cost_estimate for each goal.
Only change scores where the new information is directly relevant.
[{{"goal_id": str, "impact": float, "urgency": float, "cost_estimate": float}}]
"""

def reprioritize(
    client: anthropic.Anthropic,
    mission: str,
    goals: list[GoalPriority],
    update: str,
) -> list[GoalPriority]:
    goals_text = "\n".join(
        f"  {g.goal_id}: {g.objective} "
        f"(impact={g.impact:.2f}, urgency={g.urgency:.2f}, cost={g.cost_estimate:.1f})"
        for g in goals
    )
    prompt = REPRIORITIZE_PROMPT.format(
        mission=mission, update=update, goals_text=goals_text
    )
    resp = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[{"role":"user","content":prompt}],
    )
    raw = resp.content[0].text
    m = re.search(r"\[.*\]", raw, re.DOTALL)
    if not m:
        return goals
    updates = {d["goal_id"]: d for d in json.loads(m.group())}
    for goal in goals:
        if goal.goal_id in updates:
            u = updates[goal.goal_id]
            goal.impact = u.get("impact", goal.impact)
            goal.urgency = u.get("urgency", goal.urgency)
            goal.cost_estimate = u.get("cost_estimate", goal.cost_estimate)
    return sort_goals(goals)
